const hoy = new Date();
const tresDias = 3 * 24 * 60 * 60 * 1000; // 3 días en milisegundos
const resultados = [];

for (const item of items) {
  const fechaStr = item.json["Fecha"];
  if (!fechaStr) continue;

  // Parseo flexible de fechas tipo dd/mm/yyyy o yyyy-mm-dd
  let partes;
  let fecha;
  if (fechaStr.includes("/")) {
    partes = fechaStr.split("/");
    fecha = new Date(partes[2], partes[1] - 1, partes[0]);
  } else if (fechaStr.includes("-")) {
    partes = fechaStr.split("-");
    fecha = new Date(partes[0], partes[1] - 1, partes[2]);
  } else continue;

  const diferencia = fecha - hoy;

  // Solo si faltan entre 0 y 3 días (y aún no pasó)
  if (diferencia > 0 && diferencia <= tresDias) {
    resultados.push({
      json: {
        materia: item.json["Nombre materia"],
        tipo_examen: item.json["Tipo Examen"],
        fecha: fechaStr,
        dias_restantes: Math.ceil(diferencia / (24 * 60 * 60 * 1000))
      }
    });
  }
}

return resultados;

